### 3. Реализация системы сборки (`gulpfile.js`)

Создайте файл `gulpfile.js` со следующим кодом. Он реализует логику генерации парсера, компиляции шаблонов и формирования финальной структуры.

```javascript
const gulp = require('gulp');
const fs = require('fs-extra');
const path = require('path');
const peg = require('pegjs');
const Handlebars = require('handlebars');

// Конфигурация путей
const paths = {
    src: {
        parsers: 'src/parsers',
        templates: 'src/templates',
        assets: 'src/assets'
    },
    dist: {
        root: 'dist',
        parsers: 'dist/parsers',
        templates: 'dist/templates',
        public: 'dist/public',
        publicAssets: 'dist/public/assets'
    }
};

// 1. Задача: Генерация парсера из грамматики PEG.js
// Предполагается, что в src/parsers/grammar.pegjs есть описание грамматики
gulp.task('generate-parser', async () => {
    const grammarPath = path.join(paths.src.parsers, 'grammar.pegjs');
    const outputPath = path.join(paths.dist.parsers, 'parser.js');

    // Проверка существования файла
    if (!await fs.pathExists(grammarPath)) {
        console.warn('Файл грамматики не найден, пропускаем генерацию парсера.');
        return;
    }

    const grammar = await fs.readFile(grammarPath, 'utf-8');

    try {
        // Генерация кода парсера
        const parserCode = peg.generate(grammar, {
            output: 'source',
            format: 'commonjs'
        });

        // Запись сгенерированного файла
        await fs.outputFile(outputPath, parserCode);
        console.log(`✅ Парсер сгенерирован: ${outputPath}`);
    } catch (error) {
        console.error('❌ Ошибка генерации парсера:', error.message);
        throw error;
    }
});

// 2. Задача: Компиляция шаблонов Handlebars
gulp.task('compile-templates', async () => {
    const srcPattern = path.join(paths.src.templates, '*.hbs');
    const files = await fs.readdir(paths.src.templates);

    for (const file of files) {
        if (file.endsWith('.hbs')) {
            const inputPath = path.join(paths.src.templates, file);
            const outputPath = path.join(paths.dist.templates, file.replace('.hbs', '.js'));

            const templateSource = await fs.readFile(inputPath, 'utf-8');

            // Компиляция шаблона в JS-функцию
            const compiledTemplate = Handlebars.compile(templateSource);

            // Оборачиваем в модуль для удобства использования
            const moduleCode = `
module.exports = function(data) {
    return ${compiledTemplate.toString()}(data);
};
            `;

            await fs.outputFile(outputPath, moduleCode);
            console.log(`✅ Шаблон скомпилирован: ${outputPath}`);
        }
    }
});

// 3. Задача: Копирование статических ассетов и создание публичной структуры
gulp.task('copy-assets', async () => {
    // Создаем структуру публичного каталога
    const publicDirs = [
        paths.dist.public,
        paths.dist.publicAssets,
        path.join(paths.dist.public, 'images'),
        path.join(paths.dist.public, 'fonts')
    ];

    for (const dir of publicDirs) {
        await fs.ensureDir(dir);
    }

    // Копируем CSS и другие ассеты
    await fs.copy(paths.src.assets, paths.dist.publicAssets);

    // Создаем пример файла index.html в публичной папке, если его нет
    const indexPath = path.join(paths.dist.public, 'index.html');
    if (!await fs.pathExists(indexPath)) {
        const htmlContent = `
<!DOCTYPE html>
<html lang="ru">
<head>
    <meta charset="UTF-8">
    <title>Собранный проект</title>
    <link rel="stylesheet" href="assets/styles.css">
</head>
<body>
    <h1>Система сборки успешно выполнена!</h1>
    <p>Парсеры и шаблоны готовы к использованию.</p>
</body>
</html>
        `;
        await fs.outputFile(indexPath, htmlContent);
    }

    console.log('✅ Публичный каталог и ассеты созданы.');
});

// 4. Задача: Очистка предыдущей сборки
gulp.task('clean', async () => {
    await fs.remove(paths.dist.root);
    console.log('🗑️  Директория dist очищена.');
});

// 5. Главная задача сборки (оркестрация)
const build = gulp.series(
    'clean',
    gulp.parallel('generate-parser', 'compile-templates'),
    'copy-assets'
);

// Запуск по умолчанию
gulp.task('default', build);

// Задача для разработки (watch)
gulp.task('watch', () => {
    gulp.watch(path.join(paths.src.parsers, '*.pegjs'), gulp.series('generate-parser'));
    gulp.watch(path.join(paths.src.templates, '*.hbs'), gulp.series('compile-templates'));
    gulp.watch(path.join(paths.src.assets, '**/*'), gulp.series('copy-assets'));
    console.log('👀 Наблюдение за изменениями...');
});
```

### 4. Примеры исходных файлов

Чтобы система работала, создайте тестовые файлы в папке `src`.

**`src/parsers/grammar.pegjs`** (Пример простой грамматики):
